mapper.select:
SELECT a.id, a.asset_code, a.asset_name, a.asset_type, CASE a.asset_type WHEN 'station' THEN '电站' WHEN 'inverter' THEN '逆变器' WHEN 'combiner' THEN '汇流箱' WHEN 'panel' THEN '光伏组件' WHEN 'transformer' THEN '变压器' ELSE '其他' END AS asset_type_desc, a.station_id, s.station_name, a.device_sn, a.device_model, a.brand, a.specification, a.capacity, a.install_date, a.warranty_start_date, a.warranty_end_date, a.warranty_months, a.supplier, a.manufacturer, a.install_location, a.longitude, a.latitude, a.purchase_amount, a.responsible_person, a.asset_status, CASE a.asset_status WHEN 1 THEN '正常' WHEN 2 THEN '运维中' WHEN 3 THEN '已退役' WHEN 4 THEN '已报废' ELSE '未知' END AS asset_status_desc, a.qr_code_url, a.remark, a.create_time, a.update_time FROM asset a LEFT JOIN station s ON a.station_id = s.id WHERE a.deleted = 0
AND a.station_id = #{query.stationId}
AND a.asset_type = #{query.assetType}
AND a.asset_status = #{query.assetStatus}
AND ( a.asset_name LIKE CONCAT('%', #{query.keyword}, '%') OR a.asset_code LIKE CONCAT('%', #{query.keyword}, '%') OR a.device_model LIKE CONCAT('%', #{query.keyword}, '%') OR a.device_sn LIKE CONCAT('%', #{query.keyword}, '%') )
AND DATEDIFF(a.warranty_end_date, NOW()) <= 30 AND DATEDIFF(a.warranty_end_date, NOW()) > 0
AND DATEDIFF(a.warranty_end_date, NOW()) <= 0
AND DATEDIFF(a.warranty_end_date, NOW()) > 30
ORDER BY a.create_time DESC
